#!/usr/bin/env node
/**
 * gen-theme-bundle.mjs
 *
 * Generates packages/slides/src/styles/themes.css — an attribute-scoped bundle
 * containing all 5 built-in slide themes re-scoped from `:root` to
 * `[data-slides-theme="<name>"]` so they can be switched at runtime without
 * reloading the page.
 *
 * Run from repo root:
 *   node scripts/gen-theme-bundle.mjs
 *
 * The pure `generateThemeBundle` function is also exported so test suites can
 * regenerate the bundle in-process and compare it to the committed file —
 * ensuring no palette edits ship without a matching `themes.css` rebuild.
 */

import { readFileSync, writeFileSync } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const packageRoot = resolve(__dirname, '..')

const THEMES = ['dark', 'terminal', 'editorial', 'neon', 'bold']

/**
 * Default file reader — reads from the real filesystem.
 * Accepts a path string and returns UTF-8 file contents.
 * @param {string} filePath
 * @returns {string}
 */
function defaultReadFile(filePath) {
  return readFileSync(filePath, 'utf8')
}

/**
 * Pure function: generate the full `themes.css` bundle string.
 *
 * @param {(filePath: string) => string} [readFile] - Optional file reader;
 *   defaults to `fs.readFileSync`. Injected in tests to use the real FS
 *   without needing to re-resolve paths from `import.meta.url` inside the
 *   test file itself.
 * @returns {string} The complete bundle source, ready to write to themes.css.
 */
export function generateThemeBundle(readFile = defaultReadFile) {
  const themesDir = resolve(packageRoot, 'src/styles/themes')

  /** Deduplicated @import url(...) lines, hoisted to the top of the bundle. */
  const hoistedImports = []

  /** Per-theme CSS blocks with :root replaced by attribute selector. */
  const themeBlocks = []

  for (const name of THEMES) {
    const filePath = resolve(themesDir, `${name}.css`)
    const raw = readFile(filePath)

    // Extract all @import url(...) lines from anywhere in the file
    const importLineRe = /^\s*@import\s+url\([^)]+\)[^;]*;?\s*$/

    const lines = raw.split('\n')
    const importLines = []
    const bodyLines = []

    for (const line of lines) {
      if (importLineRe.test(line)) {
        importLines.push(line.trim())
      } else {
        bodyLines.push(line)
      }
    }

    // Collect hoisted @import lines — deduplicate by exact string
    for (const imp of importLines) {
      if (!hoistedImports.includes(imp)) {
        hoistedImports.push(imp)
      }
    }

    // Body: all lines except @import lines
    const body = bodyLines.join('\n')

    // Assert exactly one top-level :root selector in the body
    const rootMatches = body.match(/(^|\n)\s*:root\s*\{/g)
    if (!rootMatches || rootMatches.length === 0) {
      throw new Error(
        `[gen-theme-bundle] ${name}.css has no :root selector — cannot generate attribute-scoped block.`
      )
    }
    if (rootMatches.length > 1) {
      throw new Error(
        `[gen-theme-bundle] ${name}.css has ${rootMatches.length} :root selectors — expected exactly 1.`
      )
    }

    // Replace the first (and only) :root { with [data-slides-theme="name"] {
    const scoped = body.replace(/((?:^|\n)\s*):root(\s*\{)/, `$1[data-slides-theme="${name}"]$2`)

    themeBlocks.push(
      `/* GENERATED by scripts/gen-theme-bundle.mjs — do not edit by hand. Source: src/styles/themes/${name}.css */\n${scoped.trim()}`
    )
  }

  // CSS requires @import before any rules — hoist all imports to the very top
  const sections = [
    '/* GENERATED by scripts/gen-theme-bundle.mjs — do not edit by hand. Source: src/styles/themes/<name>.css */',
  ]
  if (hoistedImports.length > 0) {
    sections.push(...hoistedImports)
  }
  sections.push('')
  sections.push(...themeBlocks)
  sections.push('')

  return sections.join('\n')
}

// ── CLI entry point ───────────────────────────────────────────────────────────
// Only runs when executed directly (node scripts/gen-theme-bundle.mjs).
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const outFile = resolve(packageRoot, 'src/styles/themes.css')
  const output = generateThemeBundle()
  writeFileSync(outFile, output, 'utf8')
  console.log(`[gen-theme-bundle] Written: ${outFile}`)
}
